import{_ as a}from"./chunks/dashboard_01.InoLIzPU.js";import{_ as o,o as i,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"pt/getting-started/dashboard.md","filePath":"pt/getting-started/dashboard.md"}'),s={name:"pt/getting-started/dashboard.md"};function d(n,e,l,c,u,m){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="dashboard" tabindex="-1"><i class="ph ph-speedometer"></i> Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-speedometer&quot;&gt;&lt;/i&gt; Dashboard&quot;">​</a></h1><p>O <strong>Dashboard</strong> é um poderoso painel de controle e profiler dentro do jogo. Ele permite que você monitore o funcionamento do plugin, analise os tempos de frame e substitua manualmente os níveis dos Scalers diretamente numa build em execução.</p><p><img src="'+a+'" alt=""></p><h2 id="como-utilizar" tabindex="-1">Como Utilizar <a class="header-anchor" href="#como-utilizar" aria-label="Permalink to &quot;Como Utilizar&quot;">​</a></h2><p>Arraste e solte o <code>Dashboard.prefab</code> em qualquer cena do seu projeto.<br> Ele configurar-se-á automaticamente como <code>DontDestroyOnLoad</code> e permanecerá ativo durante as transições de cena.</p><div class="info custom-block"><p class="custom-block-title">Notas para Build de Produção</p><p>O Dashboard é inteiramente desacoplado do núcleo do plugin. Antes de lançar o seu jogo, simplesmente apague o prefab da cena. O sistema de Code Stripping do Unity removerá automaticamente todo o código do Dashboard da build final (evitando inchar a pasta <code>Resources</code>), mantendo um peso mínimo do projeto. O núcleo WebAP continuará rodando invisível em background.</p></div><h2 id="painel-esquerdo-controles" tabindex="-1"><i class="ph ph-sliders"></i> Painel Esquerdo (Controles) <a class="header-anchor" href="#painel-esquerdo-controles" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; Painel Esquerdo (Controles)&quot;">​</a></h2><p>O lado esquerdo do Dashboard é feito para interação em tempo real com o plugin.</p><ul><li><strong>Enable Web AP</strong><br> O interruptor global do núcleo do plugin. Se desabilitado, a otimização automática cessa e todos os parâmetros gráficos revertem para os seus valores originais (máximos).</li><li><strong>Anti Yo-Yo Protection</strong><br> Ativa ou desativa o Penalty Lockout. Se desabilitado, o plugin pode aumentar e diminuir a qualidade gráfica sem bloqueios temporários.<br><em>(Veja detalhes: <a href="./../advanced/anti-yoyo">Sistema Anti Yo-Yo</a>)</em></li><li><strong>Active Scalers</strong><br> Uma lista de todos os módulos de otimização adicionados ao sistema. <ul><li><strong>Toggle (Interruptor):</strong> Ativa ou desativa completamente um Scaler específico dinamicamente.</li><li><strong>Slider (Deslizante):</strong> Substitui manualmente o nível de qualidade (<code>Override Level</code>). Um valor de <code>0</code> significa qualidade máxima. Se você mover o slider, o Indexer deixará de gerenciar este Scaler, permitindo que você avalie visualmente o seu impacto no jogo.</li><li><strong>Resolution Mode (Modo de Resolução):</strong> Uma configuração exclusiva do <code>Resolution Scaler</code> (no modo BiRP). Permite alternar dinamicamente entre as estratégias <code>NativeBrowserScaling</code> e <code>RenderTextureScaling</code>.<br><em>(Veja detalhes: <a href="./../scalers/reference">Referência de Scalers</a>)</em></li></ul></li></ul><h2 id="painel-direito-analytics" tabindex="-1"><i class="ph ph-chart-bar"></i> Painel Direito (Analytics) <a class="header-anchor" href="#painel-direito-analytics" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-bar&quot;&gt;&lt;/i&gt; Painel Direito (Analytics)&quot;">​</a></h2><p>O lado direito exibe as métricas brutas da engine e a lógica interna do &quot;cérebro&quot; do plugin. Algoritmos Zero-GC de Média Móvel Exponencial (Exponential Moving Average) são utilizados para suavizar os gráficos.</p><h3 id="metricas-e-timings-metrics-timings" tabindex="-1">Métricas e Timings (Metrics &amp; Timings) <a class="header-anchor" href="#metricas-e-timings-metrics-timings" aria-label="Permalink to &quot;Métricas e Timings (Metrics &amp; Timings)&quot;">​</a></h3><ul><li><strong>Target Min FPS:</strong> O objetivo base de performance recuperado das suas configurações de projeto.</li><li><strong>Current FPS:</strong> A taxa de frames atual com um gráfico histórico de picos.</li><li><strong>Current Scale / DPI:</strong> O multiplicador de resolução atual. <code>1.00</code> dita a resolução nativa. Valores menores (e.g., <code>0.50</code>) denotam que o mundo 3D teve sua resolução reduzida para salvar a GPU.</li><li><strong>Frame Time / CPU Time:</strong> Tempos exatos do hardware recolhidos via <code>FrameTimingManager</code>. Eles ajudam a entender quanto tempo real o CPU gasta na lógica do frame.</li></ul><h3 id="cerebro-do-plugin-plugin-brain" tabindex="-1">Cérebro do Plugin (Plugin Brain) <a class="header-anchor" href="#cerebro-do-plugin-plugin-brain" aria-label="Permalink to &quot;Cérebro do Plugin (Plugin Brain)&quot;">​</a></h3><p>Exibe a lógica do pipeline de decisão.<br><em>(Veja detalhes: <a href="./../advanced/how-it-works">Como Funciona</a>)</em></p><ul><li><strong>Bottleneck:</strong> Identifica qual subsistema do dispositivo está atualmente a causar o atraso (<code>CPU</code>, <code>GPU</code>, <code>TargetFrameRate</code> ou <code>Unknown</code>).</li><li><strong>Action:</strong> Indica o que o Indexer pretende fazer (<code>IncreaseQuality</code>, <code>DecreaseQuality</code> ou <code>Stale</code> — se nenhuma ação for necessária).</li><li><strong>Status (abaixo da Ação):</strong> A condição do sistema: <code>Monitoring...</code> (avaliando frames), <code>Cooldown</code> (aguardando estabilidade após mudança gráfica) ou <code>Penalty Lockout</code> (a penalidade Anti Yo-Yo está ativa).</li></ul><h3 id="ativo-active" tabindex="-1">Ativo (Active) <a class="header-anchor" href="#ativo-active" aria-label="Permalink to &quot;Ativo (Active)&quot;">​</a></h3><ul><li>Uma lista de Scalers cujo nível está atualmente sendo <strong>reduzido</strong> pelo sistema para economizar performance. Se os FPS estão altos e tudo está otimizado, exibirá <code>- None</code>.</li></ul>',18)])])}const b=o(s,[["render",d]]);export{h as __pageData,b as default};
